#include <stdio.h>
#include <stdlib.h>

typedef struct SkipNode {
    int value;
    struct SkipNode** forward;
} SkipNode;

typedef struct SkipList {
    SkipNode* header;
    int level;
    int maxLevel;
} SkipList;

SkipNode* createNode(int value, int level) {
    SkipNode* node = (SkipNode*)malloc(sizeof(SkipNode));
    node->value = value;
    node->forward = (SkipNode**)malloc((level + 1) * sizeof(SkipNode*));
    for (int i = 0; i <= level; i++) node->forward[i] = NULL;
    return node;
}

SkipList* createSkipList(int maxLevel) {
    SkipList* sl = (SkipList*)malloc(sizeof(SkipList));
    sl->maxLevel = maxLevel;
    sl->header = createNode(-2147483648, maxLevel);
    sl->level = 0;
    return sl;
}

int randomLevel(int maxLevel) {
    int level = 0;
    while (rand() % 2 && level < maxLevel) level++;
    return level;
}

void insert(SkipList* sl, int value) {
    SkipNode** update = (SkipNode**)malloc((sl->maxLevel + 1) * sizeof(SkipNode*));
    SkipNode* current = sl->header;

    for (int i = sl->level; i >= 0; i--) {
        while (current->forward[i] && current->forward[i]->value < value) {
            current = current->forward[i];
        }
        update[i] = current;
    }

    int level = randomLevel(sl->maxLevel);
    if (level > sl->level) {
        for (int i = sl->level + 1; i <= level; i++) {
            update[i] = sl->header;
        }
        sl->level = level;
    }

    SkipNode* newNode = createNode(value, level);
    for (int i = 0; i <= level; i++) {
        newNode->forward[i] = update[i]->forward[i];
        update[i]->forward[i] = newNode;
    }
    free(update);
}

int search(SkipList* sl, int value) {
    SkipNode* current = sl->header;
    for (int i = sl->level; i >= 0; i--) {
        while (current->forward[i] && current->forward[i]->value < value) {
            current = current->forward[i];
        }
    }
    current = current->forward[0];
    return current && current->value == value;
}

void freeSkipList(SkipList* sl) {
    SkipNode* current = sl->header->forward[0];
    while (current) {
        SkipNode* temp = current;
        current = current->forward[0];
        free(temp->forward);
        free(temp);
    }
    free(sl->header->forward);
    free(sl->header);
    free(sl);
}

int main() {
    SkipList* sl = createSkipList(4);
    int values[] = {10, 20, 30, 40};
    for (int i = 0; i < 4; i++) {
        insert(sl, values[i]);
    }
    printf("Search 30: %d\n", search(sl, 30));
    printf("Search 50: %d\n", search(sl, 50));
    freeSkipList(sl);
    return 0;
}
