private:
    int maxLevel;
    SkipNode* header;
    int level;

    int randomLevel() {
        int level = 0;
        while (rand() % 2 && level < maxLevel) {
            level++;
        }
        return level;
    }

public:
    SkipList(int maxLevel = 4) : maxLevel(maxLevel), level(0) {
        header = new SkipNode(-2147483648, maxLevel);
    }

